import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/modal/src/modal.component.js';
const tagName = 'made-modal';
Component.define(tagName);
/**
 * @summary Modal’s focus the user’s attention exclusively on one task or piece of
 * information via a window that sits on top of the page content.
 *
 * @documentation '../stories/modal.mdx'
 *
 * @dependency made-icon-button
 * @dependency made-divider
 *
 * @fires close - Emitted when the modal is requested to close.
 *
 * @slot - The default slot - Slot the modal's main content.
 * @slot label - Slot for the modal's header label. Alternatively, you can use the `label` attribute.
 * @slot media-header - Slot for media content in the header.
 * @slot footer - Slot for the modal's footer content, typically action buttons.
 *
 * @csspart body - The modal's body section.
 * @csspart dialog - The component's base wrapper.
 * @csspart header - The modal's header section.
 * @csspart title - The modal's title element.
 * @csspart close-button - The modal's close button.
 *
 * @cssproperty --toggle-duration - The animation duration when opening and closing the modal.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onClose: 'close'
    },
    displayName: 'MadeModal'
});
export default reactWrapper;
